<?php
namespace App\Http\Requests\Admin\Content;use App\Domain\WorldCatalog\CatalogStatus;use Illuminate\Foundation\Http\FormRequest;use Illuminate\Validation\Rule;
final class ShopRequest extends FormRequest{public function authorize(){return true;}public function rules(){$shop=$this->route('shop');return['code'=>['required','string','max:64',Rule::unique('shops','code')->ignore($shop?$shop->id:null)],'name'=>'required|string|max:255','description'=>'nullable|string','npc_id'=>'required|integer|exists:npcs,id','status'=>['required',Rule::in(CatalogStatus::values())],'starts_at'=>'nullable|date_format:Y-m-d\TH:i','ends_at'=>'nullable|date_format:Y-m-d\TH:i|after:starts_at','sort_order'=>'required|integer|min:0','zone_ids'=>'nullable|array','zone_ids.*'=>'integer|distinct|exists:zones,id','shop_banner'=>'nullable|file|max:5120|mimetypes:image/png,image/jpeg,image/webp','remove_shop_banner'=>'nullable|boolean','shop_background'=>'nullable|file|max:5120|mimetypes:image/png,image/jpeg,image/webp','remove_shop_background'=>'nullable|boolean'];}}
